html: {"code":"<html><head><link rel="stylesheet" href="style.css"></head><body><div class='max-w-screen-md mx-auto pt-20 text-center'><p id='text' class='text'>NEON GLOW TEXT</p></div><script src="script.js"></script></body></html>"}
css: {"code":"@layer components;
.	ext-{text-5xl sm:text-7xl md:text-9xl font-bold text-shadow}

@layer components;
.	ext:hover {
	box-shadow: 0px 0px 100px #03a9f4;
	color:#03a9f4 
}

@layer components;
.neon-glow {
	transition: box-shadow 0.5s ease-in-out;
}

@layer components;
.text-container {
	position: relative;
}

@layer components;
.text-after {
	position: absolute;
	op: 0;
	left: 0;
	width: 100%;
	height: 100%;
	background-color: #03a9f4;
	clip-path: inset(0px 0px 0px 0px);
	transition: clip-path 0.5s ease-in-out;
}

@layer components;
.text-before {
	position: absolute;
	bottom: 0;
	right: 0;
	width: 100%;
	height: 100%;
	background-color: #03a9f4;
	clip-path: inset(0px 0px 0px 0px);
	transition: clip-path 0.5s ease-in-out;
}
","style":"/* Add style as needed */"}
js: {"code":"const textElement = document.getElementById('text');

const textContainer = document.createElement('div');
	extContainer.classList.add('text-container');
	extContainer.appendChild(textElement);
	document.body.appendChild(textContainer);

const textBefore = document.createElement('div');
	extBefore.classList.add('text-before', 'neon-glow');
	extBefore.style.clipPath = 'inset(0px 0px 0px 0px)';
	extContainer.appendChild(textBefore);

const textAfter = document.createElement('div');
	extAfter.classList.add('text-after', 'neon-glow');
	extAfter.style.clipPath = 'inset(0px 0px 0px 0px)';
	extContainer.appendChild(textAfter);

textElement.addEventListener('mouseover', () => {
	extBefore.style.clipPath = 'polygon(100% 0%, 100% 0%, 100% 100%, 100% 100%)';
	extAfter.style.clipPath = 'polygon(0% 0%, 0% 0%, 0% 100%, 0% 100%)';
});

textElement.addEventListener('mouseout', () => {
	extBefore.style.clipPath = 'inset(0px 0px 0px 0px)';
	extAfter.style.clipPath = 'inset(0px 0px 0px 0px)';
});"}
